add({id:"roy",logo:{type:"nfl"},q:{top:"VOTED TOP 5",main:"OROY",sub:"SAME SEASON"},w:1.5,fn:function(p,s){return nflFlag(s.roy)||(num0(s.royPlace)>0&&num0(s.royPlace)<=5);}});
