add({id:"neverAp",logo:{type:"nfl"},q:{top:"NEVER BEEN",main:"ALL-PRO",sub:"ANYTIME IN CAREER"},w:1,fn:function(p){return !p.seasons.some(function(s){return nflFlag(s.ap1)||nflFlag(s.ap2);});}});
topCollegeNames.forEach(function(col){
add({id:"col_"+col.replace(/[^a-z0-9]+/ig,"_").toLowerCase(),logo:{type:"college",college:col,sport:"NFL"},q:{isCollege:true,college:col},w:8,isCollege:true,fn:function(p){return (p&&p.col||"").trim()===col;}});
});
