function getCanonicalTeam(sport, team){
  var t=(team||"").toUpperCase().trim();
  if(!t) return "";
  if(sport==="NFL") return canonTeam(t);
  if(sport==="NBA") return NBA_TEAM_ALIASES[t]!==undefined?NBA_TEAM_ALIASES[t]:t;
  if(sport==="MLB") return MLB_TEAM_META[t]?MLB_TEAM_META[t].key:t;
  if(sport==="NHL") return NHL_TEAM_ALIASES[t]||t;
  return t;
}
function getTeamMeta(team, sport){
  var raw=(team||"").toUpperCase().trim();
  var key=getCanonicalTeam(sport, raw);
  if(sport==="MLB"){
    var mlbMeta=MLB_TEAM_META[raw]||MLB_TEAM_META[key];
    if(mlbMeta) return {raw:raw,key:mlbMeta.key,meta:Object.assign({c:mlbMeta.c},MLB_TEAMS[mlbMeta.key]||{})};
  }
  var teams=sport==="NFL"?NFL_TEAMS:sport==="NBA"?NBA_TEAMS:sport==="MLB"?MLB_TEAMS:NHL_TEAMS;
  return {raw:raw,key:key,meta:(teams&&teams[key])||null};
}
function getEspnLeagueLogoSrc(sport){
  var s=(""+(sport||"")).toLowerCase();
  if(!s) return null;
  return "https://a.espncdn.com/i/teamlogos/leagues/500/"+s+".png";
}
function getEspnTeamLogoSrc(sport, team){
  var s=(""+(sport||"")).toUpperCase().trim();
  var info=getTeamMeta(team, s);
  var key=(info&&info.key?info.key:team||"").toLowerCase();
  if(!s||!key) return null;
  var overrides={
    NHL:{LAK:"la",SJS:"sj",TBL:"tb"},
    NBA:{NOP:"no",UTA:"utah"}
  };
  var canon=(info&&info.key?info.key:"").toUpperCase();
  if(overrides[s]&&overrides[s][canon]) key=overrides[s][canon];
  return "https://a.espncdn.com/i/teamlogos/"+s.toLowerCase()+"/500/"+key+".png";
}

