// Career championship wins computed as a "stat" from season history
function careerChamps(p){ return p.seasons.reduce(function(n,s){return n+(s.champ||0);},0); }
function careerWS(p){ return p.seasons.reduce(function(n,s){return n+(s.ws||0);},0); }
function careerSC(p){ return p.seasons.reduce(function(n,s){return n+(s.champ||0);},0); }
// NFL SB wins come from the season sb flag
function careerSB(p){ return p.seasons.reduce(function(n,s){return n+(s.sb||0);},0); }
function careerReturnTds(p){ return p.seasons.reduce(function(n,s){return n+(s.returnTds||0);},0); }

