var NBA_CONSTRAINTS=buildNBAConstraints();
var MLB_CONSTRAINTS=buildMLBConstraints();
var NHL_CONSTRAINTS=buildNHLConstraints();

// ── SPORT DATA LOOKUP ────────────────────────────────────────────────────
function getSportData(sport){
  if(sport==="NFL") return {players:NFL_PLAYERS,pmap:NFL_PMAP,constraints:buildConstraints(NFL_PLAYERS),cats:SPORT_CATS.NFL,teams:NFL_TEAMS};
  if(sport==="NBA") return {players:NBA_PLAYERS,pmap:NBA_PMAP,constraints:buildNBAConstraints(NBA_PLAYERS),cats:SPORT_CATS.NBA,teams:NBA_TEAMS};
  if(sport==="MLB") return {players:MLB_PLAYERS,pmap:MLB_PMAP,constraints:MLB_CONSTRAINTS,cats:SPORT_CATS.MLB,teams:MLB_TEAMS};
  if(sport==="NHL") return {players:NHL_PLAYERS,pmap:NHL_PMAP,constraints:NHL_CONSTRAINTS,cats:SPORT_CATS.NHL,teams:NHL_TEAMS};
  return null;
}
function buildConstraintsForSport(sport,players){
  if(sport==="NFL") return buildConstraints(players||[]);
  if(sport==="NBA") return buildNBAConstraints(players||[]);
  if(sport==="MLB") return MLB_CONSTRAINTS;
  if(sport==="NHL") return NHL_CONSTRAINTS;
  return [];
}

// ── ENHANCED getSportData ──────────────────────────────────────────────────
// Returns merged local+live players
function getLiveSportData(sport){
  var base=getSportData(sport);
  if(!base) return null;
  var livePlayers=LIVE_DB[sport]||[];
  var livePmap=LIVE_PMAP[sport]||{};
  var merged={},players=[];
  (base.players||[]).forEach(function(p){
    var k=getPlayerStoreKey(p);
    if(!k||merged[k]) return;
    merged[k]=p;
    players.push(p);
  });
  livePlayers.forEach(function(p){
    var k=getPlayerStoreKey(p);
    if(!k) return;
    if(!merged[k]){
      merged[k]=p;
      players.push(p);
      return;
    }
    var target=merged[k];
    if(p.id&&!target.id) target.id=p.id;
    if(p.espnId&&!target.espnId) target.espnId=p.espnId;
    if(p.headshot&&!target.headshot) target.headshot=p.headshot;
    if(p.col&&!target.col) target.col=p.col;
    if(p.colConf&&!target.colConf) target.colConf=p.colConf;
  });
  var constraints=buildConstraintsForSport(sport,players);
  return Object.assign({},base,{
    players:players,
    pmap:Object.assign({},base.pmap,livePmap),
    constraints:getSupportedConstraints(sport,players,constraints),
    liveCount:livePlayers.length
  });
}

function getSupportedConstraints(sport,players,constraints){
  if(!players||!players.length) return constraints||[];
  var unsupported={
    NFL:{ids:[],prefixes:[]},
    NBA:{ids:["mvp","dpoy","roy","allnba1","allstar","champ","finals","tripdbl","nochamp","nofinals"],prefixes:[]},
    MLB:{ids:["mvp","cy","roy","allstar","alds","nlds","wsmvp","battitle","gg","throws_L"],prefixes:[]},
    NHL:{ids:["hart","norris","selke","vezina","calder","champ","nosc","noscFinals"],prefixes:[]}
  };
  var block=unsupported[sport]||{ids:[],prefixes:[]};
  return (constraints||[]).filter(function(c){
    if(block.ids.indexOf(c.id)>=0) return false;
    for(var i=0;i<block.prefixes.length;i++) if(c.id.indexOf(block.prefixes[i])===0) return false;
    return true;
  });
}

// ── UTILS ─────────────────────────────────────────────────────────────────
var NFL_META_CACHE={};
var NFL_META_PENDING={};
var NFL_META_KEY_PREFIX="tpr_nfl_meta_v1|";
var NFL_SEASON_FLAG_KEYS=["ap1","ap2","pb","sb","mvp","opoy","roy","sbMvp"];
var NFL_PLACE_KEYS=["mvpPlace","opoyPlace","royPlace","droyPlace"];

function num0(v){
  if(v===true) return 1;
  if(v===false||v===null||v===undefined||v==="") return 0;
  var n=parseInt(v,10);
  return isNaN(n)?0:n;
}
function nflFlag(v){return num0(v)===1;}
function cleanText(s){return (s||"").replace(/\[[^\]]*\]/g," ").replace(/\s+/g," ").trim();}
function extractYears(text){
  var years={},m,re=/(19|20)\d{2}/g;
  while((m=re.exec(text||""))){years[parseInt(m[0],10)]=1;}
  return Object.keys(years).map(function(y){return parseInt(y,10);}).sort();
}
function ordinalNum(text){
  var t=(text||"").toLowerCase().trim();
  if(t==="first"||t==="1st") return 1;
  if(t==="second"||t==="2nd") return 2;
  if(t==="third"||t==="3rd") return 3;
  if(t==="fourth"||t==="4th") return 4;
  if(t==="fifth"||t==="5th") return 5;
  var n=parseInt(t,10);
  return isNaN(n)?0:n;
}
function applyNFLSeasonDefaults(player){
  if(!player||!player.seasons) return player;
  var draftRd=num0(player.draftRd);
  var draftPk=num0(player.draftPk);
  player.draftRd=draftRd;
  player.draftPk=draftPk;
  player.isUndrafted=(draftRd>0||draftPk>0)?0:num0(player.isUndrafted);
  player.seasons.forEach(function(s){
    NFL_SEASON_FLAG_KEYS.forEach(function(k){
      if(s[k]===undefined||s[k]===null||s[k]==="") s[k]=0;
      else s[k]=num0(s[k]);
    });
    NFL_PLACE_KEYS.forEach(function(k){
      if(s[k]===undefined||s[k]===null||s[k]==="") s[k]=0;
      else s[k]=num0(s[k]);
    });
    if(s.draftRd===undefined||s.draftRd===null||s.draftRd==="") s.draftRd=draftRd;
    else s.draftRd=num0(s.draftRd);
    if(s.draftPk===undefined||s.draftPk===null||s.draftPk==="") s.draftPk=draftPk;
    else s.draftPk=num0(s.draftPk);
  });
  return player;
}
function getNFLMetaLSKey(player){
  return NFL_META_KEY_PREFIX+((player&&player.nmL)||"");
}
function restoreNFLMetaFromLS(player){
  if(!player||typeof localStorage==="undefined") return false;
  try{
    var raw=localStorage.getItem(getNFLMetaLSKey(player));
    if(!raw) return false;
    var meta=JSON.parse(raw);
    applyNFLWikiMeta(player,meta);
    return true;
  }catch(e){return false;}
}
function persistNFLMetaToLS(player,meta){
  if(!player||typeof localStorage==="undefined") return;
  try{localStorage.setItem(getNFLMetaLSKey(player),JSON.stringify(meta));}catch(e){}
}
function applyNFLWikiMeta(player,meta){
  if(!player||!meta) return applyNFLSeasonDefaults(player);
  applyNFLSeasonDefaults(player);
  if(meta.col&&!player.col) player.col=meta.col;
  if(meta.colConf&&!player.colConf) player.colConf=meta.colConf;
  if(num0(meta.draftRd)>0) player.draftRd=num0(meta.draftRd);
  if(num0(meta.draftPk)>0) player.draftPk=num0(meta.draftPk);
  player.isUndrafted=(player.draftRd>0||player.draftPk>0)?0:num0(meta.isUndrafted||player.isUndrafted);
  var yearSets={};
  Object.keys(meta.years||{}).forEach(function(k){
    yearSets[k]={};
    (meta.years[k]||[]).forEach(function(y){yearSets[k][parseInt(y,10)]=1;});
  });
  player.seasons.forEach(function(s){
    NFL_SEASON_FLAG_KEYS.forEach(function(k){
      s[k]=yearSets[k]&&yearSets[k][parseInt(s.year,10)]?1:0;
    });
    s.mvpPlace=num0(meta.places&&meta.places.mvp&&meta.places.mvp[parseInt(s.year,10)]);
    s.opoyPlace=num0(meta.places&&meta.places.opoy&&meta.places.opoy[parseInt(s.year,10)]);
    s.royPlace=num0(meta.places&&meta.places.roy&&meta.places.roy[parseInt(s.year,10)]);
    s.droyPlace=num0(meta.places&&meta.places.droy&&meta.places.droy[parseInt(s.year,10)]);
    if(s.mvp) s.mvpPlace=1;
    if(s.opoy) s.opoyPlace=1;
    if(s.roy) s.royPlace=1;
    s.draftRd=player.draftRd||0;
    s.draftPk=player.draftPk||0;
  });
  NFL_META_CACHE[player.nmL]=true;
  return player;
}
function parseNFLWikiMetaFromHtml(html){
  if(!html||typeof DOMParser==="undefined") return null;
  var doc=new DOMParser().parseFromString(html,"text/html");
  var infobox=doc.querySelector(".infobox");
  var bodyText=cleanText(doc.body&&doc.body.textContent||"").toLowerCase();
  if(!infobox||(["nfl draft","american football","wide receiver","running back","quarterback","linebacker","cornerback","safety","tight end","defensive end","offensive tackle"].every(function(t){return bodyText.indexOf(t)<0;}))){
    return null;
  }
  var meta={draftRd:0,draftPk:0,isUndrafted:0,col:"",colConf:"Independent",years:{ap1:[],ap2:[],pb:[],sb:[],mvp:[],opoy:[],roy:[],sbMvp:[]},places:{mvp:{},opoy:{},roy:{},droy:{}}};
  infobox.querySelectorAll("tr").forEach(function(tr){
    var th=cleanText(tr.querySelector("th")&&tr.querySelector("th").textContent||"");
    var td=cleanText(tr.querySelector("td")&&tr.querySelector("td").textContent||"");
    if(/NFL draft/i.test(th)){
      if(/undrafted/i.test(td)){
        meta.isUndrafted=1;
        meta.draftRd=0;
        meta.draftPk=0;
      }
      var m=td.match(/(\d+)(?:st|nd|rd|th)\s+round,\s+(\d+)(?:st|nd|rd|th)\s+overall/i);
      if(m){
        meta.draftRd=num0(m[1]);
        meta.draftPk=num0(m[2]);
        meta.isUndrafted=0;
      }
    }
    if(/Undrafted/i.test(th)){
      meta.isUndrafted=1;
      meta.draftRd=0;
      meta.draftPk=0;
    }
    if(/^College$/i.test(th)&&td){
      meta.col=td.replace(/\s*\([^)]*\)\s*$/,"").trim();
    }
  });
  var liTexts=Array.prototype.map.call(infobox.querySelectorAll("li"),function(li){return cleanText(li.textContent);});
  liTexts.forEach(function(line){
    var years=extractYears(line);
    if(/First-team\s+All-Pro/i.test(line)) meta.years.ap1=meta.years.ap1.concat(years);
    else if(/Second-team\s+All-Pro/i.test(line)) meta.years.ap2=meta.years.ap2.concat(years);
    else if(/\bPro Bowl\b/i.test(line)) meta.years.pb=meta.years.pb.concat(years);
    else if(/\bNFL MVP\b|Most Valuable Player/i.test(line)) meta.years.mvp=meta.years.mvp.concat(years);
    else if(/Offensive Player of the Year/i.test(line)) meta.years.opoy=meta.years.opoy.concat(years);
    else if(/(Offensive )?Rookie of the Year/i.test(line)) meta.years.roy=meta.years.roy.concat(years);
    else if(/Super Bowl MVP/i.test(line)) meta.years.sbMvp=meta.years.sbMvp.concat(years);
    else if(/Super Bowl champion/i.test(line)) meta.years.sb=meta.years.sb.concat(years);
  });
  Object.keys(meta.years).forEach(function(k){
    var seen={};
    meta.years[k]=(meta.years[k]||[]).filter(function(y){
      y=parseInt(y,10);
      if(!y||seen[y]) return false;
      seen[y]=1;
      return true;
    }).sort();
  });
  var prose=cleanText(doc.body&&doc.body.textContent||"");
  [
    {key:"mvp",re:/In (\d{4}),[^.]{0,240}?finished (first|second|third|fourth|fifth|[1-5](?:st|nd|rd|th)?) in (?:AP )?(?:NFL )?MVP voting/ig},
    {key:"opoy",re:/In (\d{4}),[^.]{0,240}?finished (first|second|third|fourth|fifth|[1-5](?:st|nd|rd|th)?) in (?:AP )?(?:NFL )?Offensive Player of the Year voting/ig},
    {key:"roy",re:/In (\d{4}),[^.]{0,240}?finished (first|second|third|fourth|fifth|[1-5](?:st|nd|rd|th)?) in (?:AP )?(?:NFL )?Offensive Rookie of the Year voting/ig},
    {key:"droy",re:/In (\d{4}),[^.]{0,240}?finished (first|second|third|fourth|fifth|[1-5](?:st|nd|rd|th)?) in (?:AP )?(?:NFL )?Defensive Rookie of the Year voting/ig}
  ].forEach(function(spec){
    var m;
    while((m=spec.re.exec(prose))){
      var yr=num0(m[1]),place=ordinalNum(m[2]);
      if(yr&&place) meta.places[spec.key][yr]=place;
    }
  });
  return meta;
}
function fetchNFLWikiHtmlForPlayer(name){
  var slug=(name||"").trim().replace(/\s+/g,"_");
  var parseUrl="https://en.wikipedia.org/w/api.php?action=parse&prop=text&format=json&formatversion=2&origin=*&page="+encodeURIComponent(slug);
  return fetch(parseUrl)
    .then(function(r){return r.ok?r.json():Promise.reject();})
    .then(function(d){
      if(d&&d.parse&&d.parse.text) return d.parse.text;
      return Promise.reject();
    })
    .catch(function(){
      var qUrl="https://en.wikipedia.org/w/api.php?action=query&list=search&format=json&origin=*&srlimit=1&srsearch="+encodeURIComponent(name+" NFL");
      return fetch(qUrl)
        .then(function(r){return r.ok?r.json():Promise.reject();})
        .then(function(d){
          var title=d&&d.query&&d.query.search&&d.query.search[0]&&d.query.search[0].title;
          if(!title) return Promise.reject();
          var retryUrl="https://en.wikipedia.org/w/api.php?action=parse&prop=text&format=json&formatversion=2&origin=*&page="+encodeURIComponent(title);
          return fetch(retryUrl).then(function(r){return r.ok?r.json():Promise.reject();}).then(function(x){return x&&x.parse&&x.parse.text?x.parse.text:Promise.reject();});
        });
    });
}
function needsNFLMetaLookup(player,constraintId){
  if(!player) return false;
  var id=constraintId||"";
  if(id.indexOf("dr_")===0||["udfa","ap1","ap2","pb","nopb","mvp","mvp5","opoy","opoy5","roy","droy5","sbmvp","neverAp","draftTop10"].indexOf(id)>=0) return true;
  if((!num0(player.draftRd)&&!num0(player.draftPk))||num0(player.isUndrafted)&&(num0(player.draftRd)>0||num0(player.draftPk)>0)) return true;
  return false;
}
function ensureNFLPlayerMeta(player,constraintId){
  if(!player) return Promise.resolve(player);
  applyNFLSeasonDefaults(player);
  if(!needsNFLMetaLookup(player,constraintId)) return Promise.resolve(player);
  if(NFL_META_CACHE[player.nmL]) return Promise.resolve(player);
  if(restoreNFLMetaFromLS(player)){
    NFL_META_CACHE[player.nmL]=true;
    return Promise.resolve(player);
  }
  if(NFL_META_PENDING[player.nmL]) return NFL_META_PENDING[player.nmL];
  NFL_META_PENDING[player.nmL]=fetchNFLWikiHtmlForPlayer(player.nm)
    .then(function(html){
      var meta=parseNFLWikiMetaFromHtml(html);
      if(meta){
        applyNFLWikiMeta(player,meta);
        persistNFLMetaToLS(player,meta);
      }
      NFL_META_CACHE[player.nmL]=true;
      return player;
    })
    .catch(function(){
      NFL_META_CACHE[player.nmL]=true;
      return player;
    })
    .finally(function(){delete NFL_META_PENDING[player.nmL];});
  return NFL_META_PENDING[player.nmL];
}

function rng(seed){var s=seed>>>0;return function(){s=(Math.imul(1664525,s)+1013904223)>>>0;return s/4294967296;};}
function hashSeedParts(){
  var h=2166136261>>>0;
  for(var i=0;i<arguments.length;i++){
    var part=(""+(arguments[i]===undefined?"":arguments[i]));
    for(var j=0;j<part.length;j++){
      h^=part.charCodeAt(j);
      h=Math.imul(h,16777619)>>>0;
    }
    h=Math.imul(h^0x9e3779b9,16777619)>>>0;
  }
  return h>>>0;
}
function getCollegeMode(seed,sport,catId,collegeCount){
  if((sport!=="NFL"&&sport!=="NBA")||!collegeCount) return "none";
  if(sport==="NBA"){
    var nbaRoll=hashSeedParts("college",sport,catId,seed)%160;
    if(collegeCount>=5&&nbaRoll<1) return "all";
    if(nbaRoll<8) return "single";
    return "none";
  }
  var roll=hashSeedParts("college",sport,catId,seed)%80;
  if(collegeCount>=5&&roll<1) return "all";
  if(roll<10) return "single";
  return "none";
}
function getConstraintComboText(c){
  if(!c||!c.q) return "";
  if(c.q.isCollege) return c.q.college||"";
  if(c.q.isCollegeConf) return c.q.collegeConf||"";
  return [c.q.top,c.q.main].filter(Boolean).join(" ");
}
function canUseDoubleConstraint(entry){
  var c=entry&&entry.c;
  if(!c||!c.q) return false;
  if(c.q.isCollege||c.q.isCollegeConf) return false;
  if(!c.q.main) return false;
  if(c.logo&&c.logo.type==="team") return false;
  if(c.logo&&c.logo.type==="conf") return false;
  if(c.logo&&c.logo.type==="quad") return false;
  return true;
}
function buildDoubleQualificationEntries(viable,all,cat,sport){
  var source=(viable||[]).filter(canUseDoubleConstraint);
  if(source.length<2) return [];
  var combos=[],seen={};
  function rowYearsForEntry(entry){
    var years=(entry.lbAll||[]).map(function(e){return parseInt((e.s&&e.s.year)||0,10);}).filter(function(y){return !isNaN(y)&&y>0;});
    if(!years.length) return null;
    return {min:Math.min.apply(null,years),max:Math.max.apply(null,years)};
  }
  for(var i=0;i<source.length;i++){
    for(var j=i+1;j<source.length;j++){
      var a=source[i],b=source[j];
      if(!a||!b||!a.c||!b.c) continue;
      if(a.c.id===b.c.id) continue;
      var yearsA=rowYearsForEntry(a),yearsB=rowYearsForEntry(b);
      if(yearsA&&yearsB){
        if(Math.max(yearsA.min,yearsB.min)-Math.min(yearsA.max,yearsB.max)>5) continue;
      }
      var key=[a.c.id,b.c.id].sort().join("__");
      if(seen[key]) continue;
      var lbAll=all.filter(function(e){
        return cat.career?(a.c.fn(e.p,e.p.seasons[0])&&b.c.fn(e.p,e.p.seasons[0])):(a.c.fn(e.p,e.s)&&b.c.fn(e.p,e.s));
      });
      if(lbAll.length<3) continue;
      lbAll.sort(function(x,y){return y.v-x.v;});
      var qa=a.c.q||{},qb=b.c.q||{};
      combos.push({
        c:{
          id:"dbl_"+key,
          logo:a.c.logo||{type:sport.toLowerCase()},
          q:{
            top:getConstraintComboText(a.c),
            main:(qa.main||"")+(qa.main&&qb.main?" + ":"")+(qb.main||""),
            sub:"DOUBLE QUALIFICATION"
          },
          w:0.18,
          isDouble:true,
          fn:function(p,s){return cat.career?(a.c.fn(p,p.seasons[0])&&b.c.fn(p,p.seasons[0])):(a.c.fn(p,s)&&b.c.fn(p,s));}
        },
        lbAll:lbAll
      });
      seen[key]=1;
      if(combos.length>=18) return combos;
    }
  }
  return combos;
}
function calcPct(val,all,invert){
  if(!all||!all.length) return 0;
  if(invert){
    var min=Math.min.apply(null,all.filter(function(v){return v>0;}));
    if(!isFinite(min)||min<=0||val<=0) return 0;
    return Math.max(0,Math.min(100,Math.round((min/val)*100)));
  }
  var max=Math.max.apply(null,all);
  if(!isFinite(max)||max<=0||val<=0) return 0;
  return Math.max(0,Math.min(100,Math.round((val/max)*100)));
}
function ord(n){var s=["th","st","nd","rd"],v=n%100;return n+(s[(v-20)%10]||s[v]||s[0]);}

function getStatVal(s,cat,p){
  if(cat.career&&cat.careerFn) return cat.careerFn(p);
  if(!s) return 0;
  if(cat.qualify&&!cat.qualify(s,p)) return 0;
  if(cat.key==="scrimmage") return (s.rush||0)+(s.rec||0);
  if(cat.key==="rushRecTd") return (s.rushTd||0)+(s.recTd||0);
  var v=s[cat.key]||0;
  if(cat.invert&&v>0) return -v;
  return v;
}
function getStatDisplay(val,cat){
  if(cat.invert){
    var absVal=Math.abs(val);
    if(["era","gaa"].indexOf(cat.key)>=0) return absVal.toFixed(2);
    return absVal%1===0?absVal.toLocaleString():absVal.toFixed(2);
  }
  if(["avg","obp","slg","ops"].indexOf(cat.key)>=0) return val.toFixed(3);
  if(["era","gaa","ip","ps","ops","dps","gsaa"].indexOf(cat.key)>=0) return val.toFixed(2);
  if(cat.key==="ftpct") return (val*100).toFixed(1)+"%";
  if(cat.key==="war") return val.toFixed(1);
  if(cat.key==="svpct") return (val).toFixed(1)+"%";
  if(cat.career) return Math.floor(val).toString();
  if(typeof val==="number"&&val%1!==0) return val.toFixed(1);
  return typeof val==="number"?val.toLocaleString():""+val;
}
function formatSeasonValue(year,sport){
  if(year===null||year===undefined||year==="") return "";
  if(year==="CAREER") return "CAREER";
  var y=num0(year);
  if((sport==="NBA"||sport==="NHL")&&y>0) return y+"-"+String((y+1)%100).padStart(2,"0");
  return ""+year;
}
function formatSeasonRangeLabel(yl,sport){
  if(!yl||yl==="CAREER") return yl||"";
  if((sport==="NBA"||sport==="NHL")&&yl.indexOf(" to ")>=0){
    var parts=yl.split(" to ");
    return formatSeasonValue(parts[0],sport)+" to "+formatSeasonValue(parts[1],sport);
  }
  return formatSeasonValue(yl,sport);
}
function pickBestSeasonForPlayer(player,row,cat,sport){
  if(!player||!player.seasons||!row||!row.c||cat&&cat.career) return null;
  var best=null;
  player.seasons.forEach(function(s){
    if(!row.c.fn(player,s)) return;
    var v=getStatVal(s,cat,player);
    var absV=cat&&cat.invert?-v:v;
    if(!(absV>0)) return;
    if(!best||absV>best.v||(absV===best.v&&num0(s.year)>num0(best.year))) best={year:s.year,v:absV};
  });
  return best?best.year:null;
}

function filterByCat(players,cat,sport){
  return players.filter(function(p){
    if(sport==="MLB"){if(cat.pos==="H"&&p.pos!=="H")return false;if(cat.pos==="P"&&p.pos!=="P")return false;}
    if(sport==="NHL"){
      if(cat.pos==="goalie"&&!p.isGoalie)return false;
      // Skater stat cats (goals/assists/pts/hits/pim) exclude goalies
      if(!cat.pos&&!cat.career&&p.isGoalie)return false;
    }
    if(sport==="NFL"&&cat.pos){if(!cat.pos.includes(p.pos))return false;}
    return true;
  });
}

// ── CARD GENERATOR ───────────────────────────────────────────────────────
function genCard(seed,catId,sport){
  var sd=getLiveSportData(sport);
  if(!sd) return null;
  var cat=sd.cats.find(function(c){return c.id===catId;})||sd.cats[0];
  var rand=rng(seed);
  var eligPlayers=filterByCat(sd.players,cat,sport);
  var all=[];
  eligPlayers.forEach(function(p){
    if(cat.career){
      var cv=getStatVal(null,cat,p);
      if(cv>0) all.push({p:p,s:p.seasons[p.seasons.length-1],v:cv});
    } else {
      p.seasons.forEach(function(s){
        var v=getStatVal(s,cat,p);
        var absV=cat.invert?-v:v;
        if(absV>0) all.push({p:p,s:s,v:absV});
      });
    }
  });
  if(all.length<5) return null;
  var viable=[];
  sd.constraints.forEach(function(c){
    if(sport==="NHL"){
      if(cat.pos==="goalie"&&c.id==="skater") return;
      if(!cat.pos&&!cat.career){
        if(c.id==="goalie"||c.id==="gw30"||c.id==="gw35"||c.id==="goalieL"||c.id==="sv920"||c.id==="so5") return;
      }
    }
    var lbAll=all.filter(function(e){return cat.career?c.fn(e.p,e.p.seasons[0]):c.fn(e.p,e.s);});
    if(lbAll.length>0){
      lbAll.sort(function(a,b){return b.v-a.v;});
      viable.push({c:c,lbAll:lbAll});
    }
  });
  if(viable.length<5) return null;
  function isCollegeConstraint(entry){
    var c=entry&&entry.c;
    return !!(c&&(c.isCollege||(c.logo&&(c.logo.type==="college"||c.logo.type==="collegeConf"))));
  }
  function isCollegeSchoolConstraint(entry){
    var c=entry&&entry.c;
    return !!(c&&(c.isCollege||(c.logo&&c.logo.type==="college")));
  }
  function weightedPool(entries){
    var pool=[];
    entries.forEach(function(v){
      var w=Math.max(1,Math.round((v.c.w||1)*10));
      for(var i=0;i<w;i++) pool.push(v);
    });
    return pool;
  }
  function addRowFromEntry(entry,rows,used,usedC){
      var c=entry.c;
      if(usedC[c.id]) return false;
      var match=entry.lbAll.filter(function(e){return !used[e.p.nm]&&(!cat.career?c.fn(e.p,e.s):c.fn(e.p,e.p.seasons[0]));});
      if(match.length<1) return false;
      var pick=match[Math.floor(rand()*Math.min(5,match.length))];
      var lbAll=entry.lbAll;
      var ys=null,ye=null;
      function getConstraintWindowType(logo){
        if(!logo||!logo.type) return null;
        if(logo.type==="college"||logo.type==="collegeConf") return null;
        if(logo.type==="team") return "team";
        if(logo.type==="quad") return "division";
        if(logo.type==="conf") return "league";
        if(["nfl","nba","mlb","nhl"].indexOf((""+logo.type).toLowerCase())>=0) return "league";
        return null;
      }
    function getEraAge(anchor,minYear,maxYear){
      var span=Math.max(1,maxYear-minYear);
      return Math.max(0,Math.min(1,(maxYear-anchor)/span));
    }
    function pickWindowSize(kind,anchor,minYear,maxYear){
      var eraAge=getEraAge(anchor,minYear,maxYear);
      if(kind==="team"){
        var teamBase=10+Math.floor(Math.pow(rand(),2.25)*26);
        var teamBonus=Math.floor(Math.pow(eraAge,1.15)*40);
        return Math.min(75,teamBase+teamBonus);
      }
      if(kind==="division"){
        var divBase=6+Math.floor(Math.pow(rand(),1.6)*8);
        var divBonus=Math.floor(Math.pow(eraAge,1.2)*16);
        return Math.min(30,divBase+divBonus);
      }
      if(kind==="league"){
        var lgBase=3+Math.floor(rand()*3);
        var lgBonus=Math.floor(Math.pow(eraAge,1.5)*12);
        if(sport==="MLB"&&anchor<1940) lgBonus+=12+Math.floor(((1940-anchor)/54)*18);
        return Math.min(sport==="MLB"?50:18,lgBase+lgBonus);
      }
      return null;
    }
      function clampWindowBounds(kind,anchor,minYear,maxYear,size){
        if(size==null||isNaN(anchor)||isNaN(minYear)||isNaN(maxYear)) return null;
        var full=Math.max(1,maxYear-minYear+1);
        var span=Math.min(size,full);
        if(span>=full) return {ys:minYear,ye:maxYear};
        var eraAge=getEraAge(anchor,minYear,maxYear);
        var beforeBias=kind==="league"?0.18:kind==="division"?0.28:0.38;
        var maxBefore=Math.max(0,Math.min(span-1,anchor-minYear));
        var before=Math.floor(rand()*Math.max(1,Math.round(maxBefore*(1-eraAge*(1-beforeBias)))));
        var start=anchor-before;
        var end=start+span-1;
        if(start<minYear){
          start=minYear;
          end=start+span-1;
        }
        if(end>maxYear){
          end=maxYear;
          start=end-span+1;
        }
        return {ys:start,ye:end};
      }
      if(!cat.career&&c.logo){
        var windowType=getConstraintWindowType(c.logo);
        if(windowType){
          var allYears=lbAll.map(function(e){return parseInt(e.s.year,10);}).filter(function(y){return !isNaN(y)&&y>0;});
          var anchorYear=parseInt(pick.s.year,10);
          if(allYears.length&& !isNaN(anchorYear)){
            var bounds=clampWindowBounds(
              windowType,
              anchorYear,
              Math.min.apply(null,allYears),
              Math.max.apply(null,allYears),
              pickWindowSize(windowType,anchorYear,Math.min.apply(null,allYears),Math.max.apply(null,allYears))
            );
            if(bounds){
              ys=bounds.ys;
              ye=bounds.ye;
              lbAll=lbAll.filter(function(e){
                var y=parseInt(e.s.year,10);
                return !isNaN(y)&&y>=ys&&y<=ye;
              });
              if(lbAll.length<1) return false;
            }
          }
        }
      }
      var lb=lbAll.slice(0,5).map(function(e,i){return {rank:i+1,nm:e.p.nm,year:e.s.year,team:e.s.team,v:e.v};});
      var myr=lbAll.map(function(e){return e.s.year;});
      var mn=Math.min.apply(null,myr),mx=Math.max.apply(null,myr);
    var yl=cat.career?"CAREER":(mn===mx?""+mn:mn+" to "+mx);
    rows.push({c:c,yl:yl,ys:ys,ye:ye,ans:{id:pick.p.id||null,nm:pick.p.nm,pos:pick.p.pos,team:pick.s.team,year:cat.career?"CAREER":pick.s.year,v:pick.v,lb:lb,careerCat:cat.career||false}});
    used[pick.p.nm]=true;
    usedC[c.id]=true;
    return true;
  }
  var collegeViable=viable.filter(isCollegeConstraint);
  var collegeSchoolViable=viable.filter(isCollegeSchoolConstraint);
  var collegeMode=getCollegeMode(seed,sport,cat.id,collegeSchoolViable.length);
  var doubleViable=buildDoubleQualificationEntries(viable,all,cat,sport);
  var finalViable=viable.concat(doubleViable);
  var rows=[],used={},usedC={};
  var canUseCollegeBoards=(sport==="NFL"||sport==="NBA")&&collegeSchoolViable.length;
  var shouldForceAllCollege=canUseCollegeBoards&&collegeMode==="all";
  var shouldForceOneCollege=canUseCollegeBoards&&collegeMode==="single";
  if(shouldForceAllCollege){
    var allCollegePool=weightedPool(collegeSchoolViable).sort(function(){return rand()-0.5;});
    for(var aci=0;aci<allCollegePool.length&&rows.length<5;aci++) addRowFromEntry(allCollegePool[aci],rows,used,usedC);
    return rows.length===5?{rows:rows,seed:seed,catId:catId,sport:sport}:null;
  }
  if(shouldForceOneCollege){
    var collegePool=weightedPool(collegeSchoolViable).sort(function(){return rand()-0.5;});
    for(var pi=0;pi<collegePool.length&&!rows.length;pi++) addRowFromEntry(collegePool[pi],rows,used,usedC);
  }
  var fillEntries=finalViable;
  if(shouldForceOneCollege) fillEntries=finalViable.filter(function(entry){return !isCollegeConstraint(entry);});
  if(!shouldForceAllCollege&&!shouldForceOneCollege) fillEntries=finalViable.filter(function(entry){return !isCollegeConstraint(entry);});
  var sh=weightedPool(fillEntries).slice().sort(function(){return rand()-0.5;});
  for(var ci=0;ci<sh.length&&rows.length<5;ci++){
    addRowFromEntry(sh[ci],rows,used,usedC);
  }
  return rows.length===5?{rows:rows,seed:seed,catId:catId,sport:sport}:null;
}

// ── VALIDATE ─────────────────────────────────────────────────────────────
function validate(nm,year,row,cat,sport){
  var sd=getLiveSportData(sport);
  var p=sd.pmap[nm.toLowerCase()];
  if(!p) return {ok:false,err:'"'+nm+'" not found'};
  if(sport==="NFL") applyNFLSeasonDefaults(p);
  var yearN=parseInt(year)||year;
  var s=p.seasons.find(function(x){return parseInt(x.year)===parseInt(yearN);});
  if(!s) return {ok:false,err:p.nm+" did not play in "+year};
  if(!cat.career&&row&&row.ys!=null&&row.ye!=null){
    var sy=parseInt(s.year,10);
    if(isNaN(sy)||sy<row.ys||sy>row.ye) return {ok:false,err:p.nm+" is outside this row's year window in "+year};
  }
  if(!row.c.fn(p,s)) return {ok:false,err:p.nm+" does not match this constraint in "+year};
  var v=cat.career?getStatVal(null,cat,p):getStatVal(s,cat,p);
  var absV=cat.invert?-v:v;
  if(absV<=0) return {ok:false,err:p.nm+" has no stats for this category"+(cat.career?"":" in "+year)};
  var eligPlayers=filterByCat(sd.players,cat,sport);
  var av=[];
  if(cat.career){
    eligPlayers.forEach(function(x){
      if(!row.c.fn(x,x.seasons[0]||{})) return;
      var cv=getStatVal(null,cat,x);
      if(cv>0) av.push(cv);
    });
  } else {
    eligPlayers.forEach(function(x){x.seasons.forEach(function(ss){
      if(row&&row.ys!=null&&row.ye!=null){
        var y=parseInt(ss.year,10);
        if(isNaN(y)||y<row.ys||y>row.ye) return;
      }
      if(!row.c.fn(x,ss)) return;
      var sv=getStatVal(ss,cat,x);var a=cat.invert?-sv:sv;
      if(a>0) av.push(a);
    });});
  }
  var lbR=[];
  if(cat.career){
    eligPlayers.forEach(function(x){if(!row.c.fn(x,x.seasons[0]))return;var cv=getStatVal(null,cat,x);if(cv>0)lbR.push({nm:x.nm,year:x.end,team:x.seasons[x.seasons.length-1].team,v:cv});});
  } else {
    eligPlayers.forEach(function(x){x.seasons.forEach(function(ss){if(row&&row.ys!=null&&row.ye!=null){var y=parseInt(ss.year,10);if(isNaN(y)||y<row.ys||y>row.ye)return;}if(!row.c.fn(x,ss))return;var sv=getStatVal(ss,cat,x);var a=cat.invert?-sv:sv;if(a>0)lbR.push({nm:x.nm,year:ss.year,team:ss.team,v:a});});});
  }
  lbR.sort(function(a,b){return b.v-a.v;});
  return {ok:true,v:absV,pct:calcPct(absV,av,!!cat.invert),team:s.team,pos:p.pos,lb:lbR.slice(0,5)};
}

// ── STYLE ─────────────────────────────────────────────────────────────────
function pctStyle(p){
  if(p>=100) return{bg:"linear-gradient(90deg,#3e63c9 0%,#5030b5 38%,#2a0b4f 100%)",vc:"#ffffff",pc:"rgba(255,255,255,0.78)",bd:"rgba(212,194,255,0.95)",shadow:"0 0 0 1px rgba(255,255,255,0.10) inset, 0 0 18px rgba(135,113,255,0.18)"};
  if(p>=96) return{bg:"linear-gradient(90deg,#6fb9da 0%,#2a76b0 34%,#0f3f78 100%)",vc:"#f4f7fb",pc:"rgba(255,255,255,0.72)",bd:"rgba(255,255,255,0.08)",shadow:"none"};
  if(p>=90) return{bg:"linear-gradient(90deg,#b58b00 0%,#8f6d08 45%,#5a5338 100%)",vc:"#f4f1e8",pc:"rgba(255,255,255,0.70)",bd:"rgba(255,255,255,0.06)",shadow:"none"};
  return{bg:"linear-gradient(90deg,#111111 0%,#181818 52%,#101010 100%)",vc:"#f3f4f6",pc:"rgba(255,255,255,0.62)",bd:"rgba(255,255,255,0.04)",shadow:"none"};
}
var SPORT_COLORS={
  NFL:{primary:"#0d2a0d",accent:"#22c55e"},
  NBA:{primary:"#1a2a4a",accent:"#3b82f6"},
  MLB:{primary:"#3a1a1a",accent:"#ef4444"},
  NHL:{primary:"#1a1a3a",accent:"#a78bfa"},
};

// ── LOGO COMPONENT ────────────────────────────────────────────────────────
function SportLogo(props){
  var logo=props.logo,sz=props.sz||52,sport=props.sport||"NFL";
  if(!logo) return <div style={{width:sz,height:sz,background:"#333",borderRadius:6}}/>;
  if(logo.type==="team"){
    var teamSport=logo.sport||sport;
    var teamInfo=getTeamMeta(logo.val,teamSport);
    var src=getEspnTeamLogoSrc(teamSport,logo.val);
    if(src) return <div style={{width:sz,height:sz,display:"flex",alignItems:"center",justifyContent:"center"}}><img src={src} alt={logo.val} style={{width:sz,height:sz,objectFit:"contain"}}/></div>;
    var tm=teamInfo.meta||{p:"#333",s:"#888"};
    return <div style={{width:sz,height:sz,borderRadius:6,background:tm.p,display:"flex",alignItems:"center",justifyContent:"center",color:tm.s,fontFamily:"Arial Black,sans-serif",fontWeight:900,fontSize:10}}>{logo.val}</div>;
  }
  if(logo.type==="conf"){
    var confSrc=getEspnLeagueLogoSrc(logo.sport||sport);
    if(confSrc) return <div style={{width:sz,height:sz,display:"flex",alignItems:"center",justifyContent:"center"}}><img src={confSrc} alt={logo.val} style={{width:sz,height:sz,objectFit:"contain"}}/></div>;
    var bg=logo.val==="East"||logo.val==="AL"||logo.val==="AFC"?"#B22222":"#003B8E";
    return <svg width={sz} height={sz} viewBox="0 0 56 56"><rect width="56" height="56" rx="6" fill="#111"/><polygon points="28,4 52,18 52,38 28,52 4,38 4,18" fill={bg}/><text x="28" y="34" textAnchor="middle" fill="#FFF" fontFamily="Arial Black,sans-serif" fontSize="11" fontWeight="900">{logo.val}</text></svg>;
  }
  if(logo.type==="college"){
    var collegeSrc=getCollegeLogoSrc(logo.college||"");
    if(collegeSrc) return <div style={{width:sz,height:sz,display:"flex",alignItems:"center",justifyContent:"center"}}><img src={collegeSrc} alt={logo.college||"college"} style={{width:sz,height:sz,objectFit:"contain"}}/></div>;
    var fallbackLeague=(logo.sport||sport||"").toUpperCase();
    var fallbackSrc=getEspnLeagueLogoSrc(fallbackLeague);
    if(fallbackSrc) return <div style={{width:sz,height:sz,display:"flex",alignItems:"center",justifyContent:"center"}}><img src={fallbackSrc} alt={fallbackLeague} style={{width:sz,height:sz,objectFit:"contain"}}/></div>;
    return <div style={{width:sz,height:sz,borderRadius:6,background:"#1e3a5f",display:"flex",alignItems:"center",justifyContent:"center",padding:"4px"}}><div style={{color:"white",fontFamily:"Arial Black,sans-serif",fontWeight:900,fontSize:9,lineHeight:1,textAlign:"center"}}>{(logo.college||"COLLEGE").slice(0,8)}</div></div>;
  }
  if(logo.type==="collegeConf"){
    return <div style={{width:sz,height:sz,borderRadius:6,background:"#1e3a5f",display:"flex",alignItems:"center",justifyContent:"center",padding:"4px"}}><div style={{color:"white",fontFamily:"Arial Black,sans-serif",fontWeight:900,fontSize:9,textAlign:"center"}}>{(logo.collegeConf||"").slice(0,8)}</div></div>;
  }
  if(logo.type==="quad"&&logo.teams){
    // Division logo - show 4 team logos in a 2x2 grid
    return (
      <div style={{width:sz,height:sz,display:"grid",gridTemplateColumns:"1fr 1fr",gap:1,borderRadius:4,overflow:"hidden"}}>
        {logo.teams.slice(0,4).map(function(t){
          var src=getEspnTeamLogoSrc(logo.sport||sport||"NFL",t);
          return src?<img key={t} src={src} style={{width:"100%",height:"100%",objectFit:"contain",background:"#1a1f2b"}}/>:<div key={t} style={{background:"#333"}}/>;
        })}
      </div>
    );
  }
  var sColors={nba:"#C9082A",mlb:"#002D72",nhl:"#000099",nfl:"#013087",NBA:"#C9082A",MLB:"#002D72",NHL:"#000099",NFL:"#013087"};
  // Try to show real league logo first
  var leagueSrc=getEspnLeagueLogoSrc(logo.type);
  if(leagueSrc) return <div style={{width:sz,height:sz,display:"flex",alignItems:"center",justifyContent:"center"}}><img src={leagueSrc} alt={logo.type} style={{width:sz,height:sz,objectFit:"contain"}}/></div>;
  var bg2=sColors[logo.type]||"#333";
  return <div style={{width:sz,height:sz,borderRadius:6,background:bg2,display:"flex",alignItems:"center",justifyContent:"center",color:"white",fontFamily:"Arial Black,sans-serif",fontWeight:900,fontSize:11}}>{logo.type.toUpperCase()}</div>;
}

function QualCell(props){
  var q=props.q;
  if(!q) return <div style={{flex:1}}/>;
  if(q.isCollege) return <div style={{flex:1,display:"flex",flexDirection:"column",alignItems:"flex-start",justifyContent:"center",padding:"0 10px"}}><div style={{color:"#9ca3af",fontFamily:"system-ui,sans-serif",fontSize:9,fontWeight:600,letterSpacing:1,marginBottom:2}}>COLLEGE</div><div style={{color:"white",fontFamily:"Arial Black,Impact,sans-serif",fontWeight:900,fontSize:13,lineHeight:1.1}}>{q.college}</div></div>;
  if(q.isCollegeConf) return <div style={{flex:1,display:"flex",flexDirection:"column",alignItems:"flex-start",justifyContent:"center",padding:"0 10px"}}><div style={{color:"#9ca3af",fontFamily:"system-ui,sans-serif",fontSize:9,fontWeight:600,letterSpacing:1,marginBottom:2}}>COLLEGE CONF.</div><div style={{color:"white",fontFamily:"Arial Black,Impact,sans-serif",fontWeight:900,fontSize:13,lineHeight:1.1}}>{q.collegeConf}</div></div>;
  var main=q.main||"";
  var fs=main.length>12?11:main.length>8?15:main.length>5?18:22;
  return (
    <div style={{flex:1,display:"flex",flexDirection:"column",alignItems:"flex-start",justifyContent:"center",padding:"0 10px"}}>
      {q.top?<div style={{color:"#9ca3af",fontFamily:"system-ui,sans-serif",fontSize:9,fontWeight:600,letterSpacing:1,marginBottom:2}}>{q.top}</div>:null}
      <div style={{color:"white",fontFamily:"Arial Black,Impact,sans-serif",fontWeight:900,fontSize:fs,lineHeight:1.1}}>{main}</div>
      {q.sub?<div style={{background:"#374151",borderRadius:3,padding:"1px 4px",marginTop:3,color:"#9ca3af",fontFamily:"system-ui,sans-serif",fontSize:8,fontWeight:600}}>{q.sub}</div>:null}
    </div>
  );
}

// ── LIVE STATS ENGINE ─────────────────────────────────────────────────────
var SEARCH_CACHE={};
var STATS_CACHE={};
var PLAYER_CACHE={}; // name+sport -> full player obj with seasons

// ── LIVE DB: merged local + fetched players ────────────────────────────────
var LIVE_DB={NFL:[],NBA:[],MLB:[],NHL:[]};
var LIVE_KEYMAP={NFL:{},NBA:{},MLB:{},NHL:{}};
var LIVE_PMAP={NFL:{},NBA:{},MLB:{},NHL:{}};
var DB_STATUS={NFL:"idle",NBA:"idle",MLB:"idle",NHL:"idle"};
var DB_LISTENERS={NFL:[],NBA:[],MLB:[],NHL:[]};

// localStorage keys
var LS={
  NHL:"tpr_nhl_db_v11",NBA:"tpr_nba_db_v11",MLB:"tpr_mlb_db_v11",NFL:"tpr_nfl_db_v11",
  NHL_TS:"tpr_nhl_ts_v11",NBA_TS:"tpr_nba_ts_v11",MLB_TS:"tpr_mlb_ts_v11",NFL_TS:"tpr_nfl_ts_v11"
};
var CACHE_TTL=24*60*60*1000; // 24h

function isCacheFresh(sport){
  try{var ts=parseInt(localStorage.getItem(LS[sport+"_TS"])||0);return Date.now()-ts<CACHE_TTL;}
  catch(e){return false;}
}
function saveToLS(sport,arr){
  try{localStorage.setItem(LS[sport],JSON.stringify(arr));localStorage.setItem(LS[sport+"_TS"],""+Date.now());}
  catch(e){}
}
function loadFromLS(sport){
  try{var s=localStorage.getItem(LS[sport]);return s?JSON.parse(s):null;}
  catch(e){return null;}
}

// Merge fetched players into LIVE_DB
function normalizePlayerPos(sport,pos,isGoalie){
  var p=(pos||"").toUpperCase();
  if(sport==="NBA"){
    if(p.indexOf("C")>=0) return "C";
    if(p.indexOf("G")>=0) return "G";
    if(p.indexOf("F")>=0) return "F";
    if(p==="P") return "F";
    if(p==="S") return "G";
  }
  if(sport==="NHL"){
    if(isGoalie||p==="G") return "G";
    if("CLRW".indexOf(p[0])>=0) return "F";
    if(p[0]==="D") return "D";
  }
  if(sport==="MLB"){
    return p==="P"?"P":"H";
  }
  return pos||"";
}

function getLatestSeasonYear(player){
  var seasons=(player&&player.seasons)||[];
  var years=seasons.map(function(s){return parseInt(s&&s.year,10);}).filter(function(y){return !isNaN(y)&&y>0;});
  if(years.length) return Math.max.apply(null,years);
  return parseInt(player&&player.end,10)||null;
}

function getPlayerSeasonsDesc(player){
  return ((player&&player.seasons)||[])
    .map(function(s){return parseInt(s&&s.year,10);})
    .filter(function(y){return !isNaN(y)&&y>0;})
    .sort(function(a,b){return b-a;});
}

function getPlayerStoreKey(p){
  var nmL=(p&&((p.nmL)||(p.nm&&p.nm.toLowerCase())))||"";
  var pos=(p&&p.pos)||"";
  var start=parseInt((p&&p.start),10)||0;
  var end=getLatestSeasonYear(p)||0;
  if(p&&p.id) return "id:"+String(p.id);
  return "nm:"+nmL+"|"+pos+"|"+start+"|"+end;
}

function mergePlayers(sport,newPlayers){
  var existingByKey=LIVE_KEYMAP[sport];
  var existingByName=LIVE_PMAP[sport];
  newPlayers.forEach(function(p){
    p.pos=normalizePlayerPos(sport,p.pos,p.isGoalie);
    if(sport==="NFL") applyNFLSeasonDefaults(p);
    if(sport==="NHL") p.isGoalie=(p.pos==="G");
    var nameKey=p.nmL||(p.nm&&p.nm.toLowerCase())||"";
    if(!nameKey) return;
    var storeKey=getPlayerStoreKey(p);
    if(!existingByKey[storeKey]){
      existingByKey[storeKey]=p;
      LIVE_DB[sport].push(p);
    } else {
      var target=existingByKey[storeKey];
      if(p.id&&!target.id) target.id=p.id;
      if(p.espnId&&!target.espnId) target.espnId=p.espnId;
      if(p.headshot&&!target.headshot) target.headshot=p.headshot;
      if(p.col&&!target.col) target.col=p.col;
      if(p.colConf&&!target.colConf) target.colConf=p.colConf;
    }
    if(!existingByName[nameKey]||((getLatestSeasonYear(p)||0)>(getLatestSeasonYear(existingByName[nameKey])||0))){
      existingByName[nameKey]=existingByKey[storeKey];
    }
  });
}

// Notify listeners when DB updates
function notifyDB(sport){
  (DB_LISTENERS[sport]||[]).forEach(function(fn){try{fn();}catch(e){}});
}

function loadLocalDataset(sport,url,onDone){
  if(DB_STATUS[sport] === "loading" || DB_STATUS[sport] === "done"){ onDone && onDone(); return; }
  var cached=isCacheFresh(sport)?loadFromLS(sport):null;
  if(cached&&cached.length){
    mergePlayers(sport,cached);
    DB_STATUS[sport] = "done";
    notifyDB(sport);
    onDone && onDone();
    return;
  }
  DB_STATUS[sport] = "loading";
  fetch(url)
    .then(function(r){ return r.ok ? r.json() : Promise.reject(); })
    .then(function(players){
      players=players||[];
      mergePlayers(sport, players);
      saveToLS(sport, players);
      DB_STATUS[sport] = "done";
      notifyDB(sport);
      onDone && onDone();
    })
    .catch(function(){
      mergePlayers(sport, []);
      DB_STATUS[sport] = "error";
      notifyDB(sport);
      onDone && onDone();
    });
}

