          if(!yr||!r.gamesPlayed) return;
          // nhle API uses teamAbbrevs (with s) for the list, may be comma-separated for traded players
    var tmRaw=(r.teamAbbrevs||r.teamAbbrevName||r.teamAbbrev||r.teamAbbr||"");
    var tm=String(tmRaw).split(",")[0].trim()||"???";
          var gp=r.gamesPlayed||0;
