          if(cleanedQuery2&&cleanedQuery2.toLowerCase()!==nmL2&&cleanedQuery2.toLowerCase()!==stripped2) fetchJson2("https://site.web.api.espn.com/apis/common/v3/search?query="+encodeURIComponent(cleanedQuery2)+"&type=player&limit=12",useEspnResults2);
